// Split incoming contentPrompts into one item per platform
const _raw = $input.first().json;
const { postId, contentPrompts, callbackUrl } = _raw.body ?? _raw;

if (!postId || !contentPrompts || !callbackUrl) {
  throw new Error('Missing required fields: postId, contentPrompts, callbackUrl');
}

const items = [];
for (const [platform, prompts] of Object.entries(contentPrompts)) {
  if (!prompts || !prompts.systemPrompt || !prompts.userPrompt) {
    console.log(`Skipping ${platform} - missing systemPrompt or userPrompt`);
    continue;
  }
  items.push({
    json: {
      postId,
      platform,
      systemPrompt: prompts.systemPrompt,
      userPrompt: prompts.userPrompt,
      context: prompts.context || {},
      callbackUrl
    }
  });
}

if (items.length === 0) {
  throw new Error('No valid platforms with content prompts found');
}

return items;

// Parse AI Agent responses — zip by index to avoid broken item pairing
const agentOutputs = $input.all();
const splitItems = $('Code - Split by Platform').all();
const now = new Date().toISOString();

return agentOutputs.map((agentItem, i) => {
  const split = splitItems[i] || splitItems[0];
  const postId = split.json.postId;
  const platform = split.json.platform;
  const callbackUrl = split.json.callbackUrl;

  const content = agentItem.json?.output || '';
  if (!content) {
    throw new Error(`AI Agent returned empty content for ${platform}`);
  }

  const hashtagMatches = content.match(/#[\w]+/g) || [];
  const hashtags = [...new Set(hashtagMatches.map(h => h.replace('#', '').toLowerCase()))];
  const text = content.trim();

  return {
    json: {
      postId,
      platform,
      callbackUrl,
      text,
      hashtags,
      status: 'pending',
      generatedAt: now,
      action: 'UPDATE_PLATFORM_VARIANT',
      payload: { postId, platform, variant: { text, hashtags, status: 'pending', generatedAt: now } }
    }
  };
});

// Aggregate all platform results and prepare callback
const items = $input.all();
const postId = items[0]?.json?.postId || items[0]?.json?.post_id || '';
const callbackUrl = $('Code - Parse AI Response').all()[0]?.json?.callbackUrl || '';

return [{
  json: {
    postId,
    callbackUrl,
    status: 'done',
    processedPlatforms: items.length
  }
}];

// Build error callback payload
const inputData = $input.first().json || {};
// Try to get callbackUrl from the original webhook data
let callbackUrl = '';
let postId = '';
try {
  const _wh = $('Webhook').first().json;
  const _whBody = _wh.body ?? _wh;
  callbackUrl = _whBody.callbackUrl || '';
  postId = _whBody.postId || '';
} catch(e) {}

return [{
  json: {
    postId,
    callbackUrl,
    status: 'failed',
    error: inputData.error?.message || 'Content generation failed'
  }
}];
